mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rn, A.* FROM ( SELECT p.prod_no AS productId, p.prod_nm AS productName, p.prod_type AS productType, p.tgt_lrg AS targetLarge, p.tgt_dtl AS targetDetail, TO_CHAR(DBMS_LOB.SUBSTR(p.prod_desc, 1000, 1)) AS productDesc, p.rate_cat AS rateCategory, p.active AS isActive, p.reg_dt AS createdAt, p.min_prd_mon AS minPeriodMonth, p.max_prd_mon AS maxPeriodMonth, p.min_amt AS minAmount, p.max_amt AS maxAmount, p.app_start_dt AS appStartDate, p.app_end_dt AS appEndDate, NVL(MIN(r.base_rate), 0) AS minRate, NVL(MAX(r.base_rate + NVL(r.pref_rate, 0)), 0) AS maxRate FROM products p LEFT JOIN interest_rates r ON p.prod_no = r.prod_no AND r.is_active = 'Y' WHERE 1=1 AND p.active = 'Y' AND p.apv_stat_cd = '승인'
AND p.prod_type IN ('FOREIGN_DEP', 'FOREIGN_SAV')
AND p.rate_cat = #{rateCategory}
AND ( p.prod_nm LIKE '%' || #{keyword} || '%' OR DBMS_LOB.INSTR(p.prod_desc, #{keyword}) > 0 )
AND p.prod_type = #{productType}
AND ( p.tgt_lrg = #{targetLarge} OR p.tgt_lrg = 'ALL' )
AND ( p.tgt_dtl = #{targetDetail} OR p.tgt_dtl = 'ALL' )
GROUP BY p.prod_no, p.prod_nm, p.prod_type, p.tgt_lrg, p.tgt_dtl, TO_CHAR(DBMS_LOB.SUBSTR(p.prod_desc, 1000, 1)), p.rate_cat, p.active, p.reg_dt, p.min_prd_mon, p.max_prd_mon, p.min_amt, p.max_amt, p.app_start_dt, p.app_end_dt
ORDER BY maxRate DESC
ORDER BY p.prod_nm ASC
ORDER BY p.reg_dt DESC
) A WHERE ROWNUM <= #{endRow} ) WHERE rn >= #{startRow}

SELECT COUNT(*)
FROM products p
WHERE 1=1
  AND p.active = 'Y'
  AND p.apv_stat_cd = '승인'


    AND p.prod_type IN ('FOREIGN_DEP', 'FOREIGN_SAV')



    AND p.rate_cat = #{rateCategory}



    AND (
        p.tgt_lrg = #{targetLarge}
        OR p.tgt_lrg = 'ALL'
    )



    AND (
        p.tgt_dtl = #{targetDetail}
        OR p.tgt_dtl = 'ALL'
    )



    AND p.prod_type = #{productType}



    AND (
        p.prod_nm LIKE '%' || #{keyword} || '%'
        OR DBMS_LOB.INSTR(p.prod_desc, #{keyword}) > 0
    )
